class Solution {
public:
    int numberOfArrays(string s, int k) {
        int n = s.size();
        long long dp[n + 1];
        dp[0] = 1;
        long long mod = 1e9 + 7;
        for (int i = 1; i <= n; i++) {
            dp[i] = 0;
            int num = 0;
            for (int j = i - 1; j >= 0; j--) {
                num = num * 10 + (s[j] - '0');
                if (num <= k && num != 0) {
                    dp[i] = (dp[i] + dp[j] * (k / num)) % mod;
                }
            }
        }
        return dp[n];
    }
};
